import{_ as s,o as n,c as e,ak as r}from"./chunks/framework.DwHlt8HN.js";const b=JSON.parse('{"title":"基础设施即代码（IaC）","description":"","frontmatter":{},"headers":[],"relativePath":"devops/iac/index.md","filePath":"devops/iac/index.md","lastUpdated":1774320699000}'),p={name:"devops/iac/index.md"};function l(i,a,t,o,c,d){return n(),e("div",null,[...a[0]||(a[0]=[r(`<h1 id="基础设施即代码-iac" tabindex="-1">基础设施即代码（IaC） <a class="header-anchor" href="#基础设施即代码-iac" aria-label="Permalink to “基础设施即代码（IaC）”">​</a></h1><p>代码化的基础设施，是云时代运维的必然归宿。</p><p>传统运维里，改一台服务器的配置，要么是登上去手动改，要么是写个脚本传上去。问题在于：改了之后怎么保证幂等？出了问题怎么回滚？谁改的、什么时候改的、为什么改？</p><p>IaC（Infrastructure as Code）用写代码的方式管理基础设施：所有配置都在代码仓库里，有版本历史、可审计、可回滚、可复用。Terraform、Pulumi、Ansible，都是这个理念的践行者。</p><p>这篇文章系列覆盖 Terraform 基础与 HCL 语法、模块化与状态管理、Pulumi 编程式 IaC，以及工具选型对比，帮助你从「手工作坊式运维」过渡到「工程化运维」。</p><h2 id="模块速览" tabindex="-1">模块速览 <a class="header-anchor" href="#模块速览" aria-label="Permalink to “模块速览”">​</a></h2><p>IaC 工具的三条路线：声明式（HCL）、编程式（SDK）、配置管理式（YAML/Ansible）。每条路线都有它的适用场景。</p><table tabindex="0"><thead><tr><th>方向</th><th>篇数</th><th>核心目标</th></tr></thead><tbody><tr><td><a href="/devops/iac/terraform">Terraform 基础与 HCL 语法</a></td><td>1 篇</td><td>声明式语法、资源管理、Provider 生态</td></tr><tr><td><a href="/devops/iac/terraform-module">Terraform 模块化与状态管理</a></td><td>1 篇</td><td>模块复用、远程状态、状态锁定</td></tr><tr><td><a href="/devops/iac/pulumi">Pulumi：用代码管理云资源</a></td><td>1 篇</td><td>编程式 IaC、TypeScript/Python 支持</td></tr><tr><td><a href="/devops/iac/compare">Ansible vs Terraform vs Pulumi 对比</a></td><td>1 篇</td><td>三种路线的选型决策</td></tr></tbody></table><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to “学习路径建议”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第一阶段：Terraform 入门（1 周）</span></span>
<span class="line"><span>→ 理解声明式 vs 命令式配置的区别</span></span>
<span class="line"><span>→ 掌握 HCL 语法：resource、variable、output、data</span></span>
<span class="line"><span>→ 编写第一个 Terraform 配置文件（创建 VPC、EC2）</span></span>
<span class="line"><span>→ 状态管理：本地 vs 远程（ S3 + DynamoDB）</span></span>
<span class="line"><span>→ 引入模块化：抽取可复用组件</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二阶段：Terraform 进阶（1 周）</span></span>
<span class="line"><span>→ Provider 配置与多云支持</span></span>
<span class="line"><span>→ 工作区（Workspace）实现环境隔离</span></span>
<span class="line"><span>→ 远程状态锁定与并发控制</span></span>
<span class="line"><span>→ 敏感信息管理：Vault 集成或 Sensitive 标记</span></span>
<span class="line"><span>→ 迁移与导入已有资源</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三阶段：Pulumi 入门（2-3 天）</span></span>
<span class="line"><span>→ Pulumi vs Terraform 的核心差异</span></span>
<span class="line"><span>→ 用 TypeScript/Python/Pulumi 管理云资源</span></span>
<span class="line"><span>→ 熟悉 Pulumi 的 Stack 概念与状态管理</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第四阶段：选型与融合（1 周）</span></span>
<span class="line"><span>→ 什么场景用 Terraform？什么场景用 Ansible？</span></span>
<span class="line"><span>→ Pulumi 的优势：循环、条件、函数式逻辑</span></span>
<span class="line"><span>→ 团队 IaC 实践：目录结构、代码审查、CI/CD 集成</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br></div></div><h2 id="声明式-vs-编程式-两条路线的取舍" tabindex="-1">声明式 vs 编程式：两条路线的取舍 <a class="header-anchor" href="#声明式-vs-编程式-两条路线的取舍" aria-label="Permalink to “声明式 vs 编程式：两条路线的取舍”">​</a></h2><p>Terraform 和 Pulumi 代表了 IaC 的两条主流路线：</p><p><strong>Terraform（声明式）</strong>：</p><ul><li>用 HCL 语言描述「最终状态」</li><li>你声明「我要 3 台机器，带这个配置」，Terraform 计算出「怎么做」</li><li>优势：语法简洁、状态管理内置、社区成熟（Provider 生态丰富）</li><li>局限：逻辑表达能力弱，循环和条件需要借助语言扩展</li></ul><p><strong>Pulumi（编程式）</strong>：</p><ul><li>用熟悉的编程语言（TypeScript、Python、Go）写代码</li><li>你用代码描述「怎么创建这些资源」，Pulumi 执行代码来创建</li><li>优势：逻辑表达能力完整，可以复用已有的代码库</li><li>局限：状态管理需要额外考虑，团队学习成本更高</li></ul><p>没有绝对的优劣，只有场景的匹配度——基础设施定义用 Terraform，复杂配置管理用 Ansible，需要复杂逻辑的地方用 Pulumi。</p><h2 id="面试的核心逻辑" tabindex="-1">面试的核心逻辑 <a class="header-anchor" href="#面试的核心逻辑" aria-label="Permalink to “面试的核心逻辑”">​</a></h2><p>IaC 的面试，核心在于考察你对「工程化运维」的理解：</p><ol><li><strong>基础概念</strong>：声明式和命令式的区别是什么？为什么 IaC 比手动运维更可靠？</li><li><strong>Terraform 原理</strong>：Terraform 的状态文件存储了什么？为什么不能删除？如何处理状态锁定？</li><li><strong>模块化思维</strong>：如何设计可复用的 Terraform 模块？模块的版本怎么管理？</li><li><strong>工程实践</strong>：多环境（dev、staging、prod）怎么隔离？敏感信息怎么处理？</li><li><strong>工具选型</strong>：为什么很多团队同时用 Terraform 和 Ansible？它们各自解决什么问题？</li></ol><blockquote><p>&quot;IaC 的本质是把「确定性」引入运维。好的 IaC 设计，应该是任何一个人 Checkout 代码后，都能跑出一套一模一样的环境。&quot;</p></blockquote>`,21)])])}const m=s(p,[["render",l]]);export{b as __pageData,m as default};
